  "type": "module",
  "description": "Pagewright landing/marketing starter — Astro + shared blocks, deploys to GitHub Pages.",
  "scripts": {
    "dev": "astro dev",
    "build": "astro build",
    "preview": "astro preview",
    "typecheck": "astro check"
  },
  "dependencies": {
    "@astrojs/react": "^4.2.0",
    "@pagewright/blocks": "workspace:*",
    "@pagewright/site-kit": "workspace:*",
    "astro": "^5.2.0",
