import { parsePost, type Post } from "@pagewright/blocks";

/**
 * Loads blog posts from `src/data/posts/*.json` at build time. Each post is validated against the
 * shared `postSchema`, so malformed content fails the build loudly. The post `slug` is derived from
 * the filename when not set explicitly.
 */
const modules = import.meta.glob<{ default: unknown }>("../data/posts/*.json", {
  eager: true,
});

export interface LoadedPost extends Post {
  slug: string;
}

export function getAllPosts(): LoadedPost[] {
  return Object.entries(modules).map(([path, mod]) => {
    const post = parsePost(mod.default);
    const file = path.split("/").pop()!.replace(/\.json$/, "");
    const slug = post.slug && post.slug !== "/" ? post.slug.replace(/^\/+/, "") : file;
    return { ...post, slug };
  });
}

/** Published posts (not draft, and `publishAt` in the past), newest first. */
export function getPublishedPosts(now: Date = new Date()): LoadedPost[] {
  return getAllPosts()
    .filter((p) => !p.draft && (!p.publishAt || new Date(p.publishAt) <= now))
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
}

---
import Layout from "../../layouts/Layout.astro";
import { PageRenderer, PostHeader } from "@pagewright/blocks";
import { getPublishedPosts, type LoadedPost } from "../../lib/posts";

export function getStaticPaths() {
  return getPublishedPosts().map((post) => ({
    params: { slug: post.slug },
    props: { post },
  }));
}

interface Props {
  post: LoadedPost;
}

const { post } = Astro.props;
const base = import.meta.env.BASE_URL;
---

<Layout title={post.title} description={post.description ?? post.excerpt}>
  <PostHeader
    title={post.title}
    date={post.date}
    author={post.author}
    tags={post.tags}
  />
  <PageRenderer blocks={post.blocks} base={base} />
  <div class="pw-section" style="padding-block: 0 72px;">
    <div class="pw-container" style="max-width: 720px;">
      <a class="pw-postback" href={base}>← Back to all posts</a>
    </div>
  </div>
</Layout>

<style>
  .pw-postback {
    color: hsl(var(--pw-primary));
    text-decoration: none;
    font-weight: 600;
  }
  .pw-postback:hover {
    text-decoration: underline;
  }
</style>

---
import Layout from "../layouts/Layout.astro";
import { PageRenderer, PostList, parsePage } from "@pagewright/blocks";
import homeDoc from "../data/pages/home.json";
import { getPublishedPosts } from "../lib/posts";

const page = parsePage(homeDoc);
const base = import.meta.env.BASE_URL;

const posts = getPublishedPosts().map((p) => ({
  title: p.title,
  href: `/blog/${p.slug}/`,
  date: p.date,
  excerpt: p.excerpt,
  cover: p.cover,
  tags: p.tags,
}));

// Render authored header blocks, then the derived post list, then the footer.
const footerIndex = page.blocks.findIndex((b) => b.type === "footer");
const headBlocks = footerIndex >= 0 ? page.blocks.slice(0, footerIndex) : page.blocks;
const footerBlocks = footerIndex >= 0 ? page.blocks.slice(footerIndex) : [];
---

<Layout title={page.title} description={page.description}>
  <PageRenderer blocks={headBlocks} base={base} />
  <PostList heading="Latest posts" posts={posts} base={base} />
  <PageRenderer blocks={footerBlocks} base={base} />
</Layout>

