/**
 * Base-path awareness for generated sites.
 *
 * GitHub Pages *project* sites are served from `/<repo>/`, so a root-relative asset like an uploaded
 * image (`/media/logo.png`) or an internal link (`/blog/hello/`) would 404 unless it is prefixed with
 * the site's base path. Astro exposes that value as `import.meta.env.BASE_URL` (always `/`-terminated,
 * e.g. `/my-repo/` or `/`), which the templates thread into {@link PageRenderer} via the `base` prop.
 * The Next.js builder preview renders from the app origin, so it simply uses the default base of `/`.
 *
 * These are plain functions (no React context) so the block components stay renderable as React
 * Server Components in the Next.js app and as static islands in Astro — `base` is threaded as an
 * explicit prop rather than through context, which RSC does not support.
 */

/** Extra prop carried by every block component so it can resolve root-relative URLs. */
export interface BaseAware {
  /** Site base path (e.g. `/my-repo/`). Defaults to `/`. */
  base?: string;
}

/** Normalize any incoming base to a leading+trailing-slashed path (or `/`). */
export function normalizeBase(base?: string | null): string {
  if (!base) return "/";
  let b = base.trim();
  if (b === "" || b === "/") return "/";
  if (!b.startsWith("/")) b = `/${b}`;
  if (!b.endsWith("/")) b = `${b}/`;
  return b;
}

/**
 * Prefix a root-relative internal URL with the site base path. Absolute URLs (`http(s)://`),
 * protocol-relative (`//cdn`), anchors (`#`), scheme URLs (`mailto:`, `tel:`, `data:`), and already
 * relative paths are returned untouched so they never get double-prefixed.
 */
export function withBase(base: string | undefined, url?: string): string | undefined {
  if (!url) return url;
  // Only root-relative internal paths get rewritten.
  if (!url.startsWith("/")) return url;
  if (url.startsWith("//")) return url;
  const b = normalizeBase(base);
  if (b === "/") return url;
  return `${b.replace(/\/$/, "")}${url}`;
}

import * as React from "react";
import type {
  BlockProps,
  BlockType,
  Link,
} from "../schema";
import { BlockIcon } from "../icons";
import { withBase, normalizeBase, type BaseAware } from "../base";

/**
 * Block components. Plain React + scoped `pw-` CSS classes (see styles/blocks.css) so they render
 * pixel-identically in the Next.js builder preview and in generated Astro sites (via @astrojs/react).
 * No Tailwind dependency here on purpose — that keeps the two consumers perfectly in sync.
 *
 * Each block accepts an optional `base` (the site base path) threaded down from PageRenderer so that
 * root-relative image/link URLs resolve on GitHub Pages project sites.
 */

function CtaLink({
  link,
  variant,
  base,
}: {
  link?: Link;
  variant: "primary" | "secondary";
  base?: string;
}) {
  if (!link) return null;
  return (
    <a className={`pw-btn pw-btn--${variant}`} href={withBase(base, link.href)}>
      {link.label}
    </a>
  );
}

export function Navbar({ brand, logo, links = [], cta, base }: BlockProps<"navbar"> & BaseAware) {
  return (
    <nav className="pw-navbar">
      <div className="pw-container pw-navbar__inner">
        <a className="pw-navbar__brand" href={withBase(base, "/")}>
          {logo ? <img className="pw-navbar__logo" src={withBase(base, logo)} alt={brand} /> : null}
          <span>{brand}</span>
        </a>
        <div className="pw-navbar__links">
          {links.map((l, i) => (
            <a key={i} className="pw-navbar__link" href={withBase(base, l.href)}>
              {l.label}
            </a>
          ))}
          <CtaLink link={cta} variant="primary" base={base} />
        </div>
      </div>
    </nav>
  );
}

export function Hero({
  eyebrow,
  heading,
  subheading,
  primaryCta,
  secondaryCta,
  image,
  align = "center",
  base,
}: BlockProps<"hero"> & BaseAware) {
  return (
    <header className={`pw-hero pw-hero--${align}`}>
      <div className="pw-container pw-hero__inner">
        <div className="pw-hero__content">
          {eyebrow ? <p className="pw-hero__eyebrow">{eyebrow}</p> : null}
          <h1 className="pw-hero__heading">{heading}</h1>
          {subheading ? <p className="pw-hero__subheading">{subheading}</p> : null}
          <div className="pw-hero__actions">
            <CtaLink link={primaryCta} variant="primary" base={base} />
            <CtaLink link={secondaryCta} variant="secondary" base={base} />
          </div>
        </div>
        {image ? (
          <div className="pw-hero__media">
            <img src={withBase(base, image)} alt={heading} />
          </div>
        ) : null}
      </div>
    </header>
  );
}

export function Features({
  heading,
  subheading,
  columns = 3,
  items = [],
}: BlockProps<"features">) {
  return (
    <section className="pw-section pw-features">
      <div className="pw-container">
        {heading ? <h2 className="pw-section__heading">{heading}</h2> : null}
        {subheading ? <p className="pw-section__subheading">{subheading}</p> : null}
        <div className={`pw-features__grid pw-cols-${columns}`}>
          {items.map((item, i) => (
            <div key={i} className="pw-feature">
              {item.icon ? (
                <div className="pw-feature__icon" aria-hidden>
                  <BlockIcon name={item.icon} size={26} />
                </div>
              ) : null}
              <h3 className="pw-feature__title">{item.title}</h3>
              <p className="pw-feature__body">{item.body}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export function Gallery({
  heading,
  subheading,
  columns = 3,
  items = [],
  base,
}: BlockProps<"gallery"> & BaseAware) {
  return (
    <section className="pw-section pw-gallery">
      <div className="pw-container">
        {heading ? <h2 className="pw-section__heading">{heading}</h2> : null}
        {subheading ? <p className="pw-section__subheading">{subheading}</p> : null}
        <div className={`pw-gallery__grid pw-cols-${columns}`}>
          {items.map((item, i) => {
            const inner = (
              <>
                {item.image ? (
                  <div className="pw-gallery__media">
                    <img src={withBase(base, item.image)} alt={item.title} loading="lazy" />
                  </div>
                ) : null}
                <div className="pw-gallery__body">
                  <h3 className="pw-gallery__title">{item.title}</h3>
                  {item.description ? (
                    <p className="pw-gallery__desc">{item.description}</p>
                  ) : null}
                  {item.tags.length > 0 ? (
                    <div className="pw-gallery__tags">
                      {item.tags.map((t, ti) => (
                        <span key={ti} className="pw-tag">
                          {t}
                        </span>
                      ))}
                    </div>
                  ) : null}
                </div>
              </>
            );
            return item.href ? (
              <a
                key={i}
                className="pw-gallery__item pw-gallery__item--link"
                href={withBase(base, item.href)}
              >
                {inner}
              </a>
            ) : (
              <div key={i} className="pw-gallery__item">
                {inner}
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

export function Cta({
  heading,
  body,
  primaryCta,
  secondaryCta,
  base,
}: BlockProps<"cta"> & BaseAware) {
  return (
    <section className="pw-section pw-cta">
      <div className="pw-container pw-cta__inner">
        <h2 className="pw-cta__heading">{heading}</h2>
        {body ? <p className="pw-cta__body">{body}</p> : null}
        <div className="pw-cta__actions">
          <CtaLink link={primaryCta} variant="primary" base={base} />
          <CtaLink link={secondaryCta} variant="secondary" base={base} />
        </div>
      </div>
    </section>
  );
}

/**
 * Rewrites root-relative `src`/`href` attributes in a prose HTML fragment to include the site base
 * path, so uploaded images (`/media/…`) and internal links resolve on GitHub Pages *project* sites.
 * Absolute/protocol-relative/anchor URLs are left untouched by {@link withBase}.
 */
function withBaseInHtml(html: string, base?: string): string {
  const b = normalizeBase(base);
  if (b === "/" || !html) return html;
  return html.replace(
    /(\b(?:src|href)=)("|')(\/[^"']*)\2/g,
    (_m, attr: string, quote: string, url: string) => `${attr}${quote}${withBase(base, url)}${quote}`,
  );
}

export function Prose({ html = "", base }: BlockProps<"prose"> & BaseAware) {
  return (
    <section className="pw-section">
      <div
        className="pw-container pw-prose"
        dangerouslySetInnerHTML={{ __html: withBaseInHtml(html, base) }}
      />
    </section>
  );
}

export function Footer({
  brand,
  tagline,
  links = [],
  copyright,
  base,
}: BlockProps<"footer"> & BaseAware) {
  return (
    <footer className="pw-footer">
      <div className="pw-container pw-footer__inner">
        <div className="pw-footer__brand">
          {brand ? <strong>{brand}</strong> : null}
          {tagline ? <p className="pw-footer__tagline">{tagline}</p> : null}
        </div>
        <div className="pw-footer__links">
          {links.map((l, i) => (
            <a key={i} className="pw-footer__link" href={withBase(base, l.href)}>
              {l.label}
            </a>
          ))}
        </div>
      </div>
      {copyright ? <div className="pw-container pw-footer__copyright">{copyright}</div> : null}
    </footer>
  );
}

/** Maps a block type to its React component. */
export const blockRegistry: {
  [K in BlockType]: React.FC<BlockProps<K>>;
} = {
  navbar: Navbar,
  hero: Hero,
  features: Features,
  gallery: Gallery,
  cta: Cta,
  prose: Prose,
  footer: Footer,
};

/** Formats an ISO date string as a readable date (build-time, locale-stable). */
export function formatDate(iso: string): string {
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return iso;
  return new Intl.DateTimeFormat("en-US", {
    year: "numeric",
    month: "short",
    day: "numeric",
    timeZone: "UTC",
  }).format(d);
}

export interface PostCard {
  title: string;
  href: string;
  date: string;
  excerpt?: string;
  cover?: string;
  tags?: string[];
}

/**
 * Renders a grid of blog post cards. Unlike the authored blocks, the post list is *derived* from a
 * repo's posts at build time, so the blog template gathers posts and passes them here directly.
 */
export function PostList({
  heading,
  subheading,
  posts,
  base,
}: {
  heading?: string;
  subheading?: string;
  posts: PostCard[];
  base?: string;
}) {
  return (
    <section className="pw-section pw-postlist">
      <div className="pw-container">
        {heading ? <h2 className="pw-section__heading">{heading}</h2> : null}
        {subheading ? <p className="pw-section__subheading">{subheading}</p> : null}
        {posts.length === 0 ? (
          <p className="pw-postlist__empty">No posts published yet — check back soon.</p>
        ) : (
          <div className="pw-postlist__grid">
            {posts.map((p, i) => (
              <a key={i} className="pw-postcard" href={withBase(base, p.href)}>
                {p.cover ? (
                  <div className="pw-postcard__media">
                    <img src={withBase(base, p.cover)} alt={p.title} loading="lazy" />
                  </div>
                ) : null}
                <div className="pw-postcard__body">
                  <time className="pw-postcard__date" dateTime={p.date}>
                    {formatDate(p.date)}
                  </time>
                  <h3 className="pw-postcard__title">{p.title}</h3>
                  {p.excerpt ? <p className="pw-postcard__excerpt">{p.excerpt}</p> : null}
                  {p.tags && p.tags.length > 0 ? (
                    <div className="pw-postcard__tags">
                      {p.tags.map((t, ti) => (
                        <span key={ti} className="pw-tag">
                          {t}
                        </span>
                      ))}
                    </div>
                  ) : null}
                </div>
              </a>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

/** Header for a single blog post page (title, date, tags). */
export function PostHeader({
  title,
  date,
  author,
  tags = [],
}: {
  title: string;
  date: string;
  author?: string;
  tags?: string[];
}) {
  return (
    <header className="pw-posthead">
      <div className="pw-container pw-posthead__inner">
        <div className="pw-posthead__meta">
          <time dateTime={date}>{formatDate(date)}</time>
          {author ? <span className="pw-posthead__author">· {author}</span> : null}
        </div>
        <h1 className="pw-posthead__title">{title}</h1>
        {tags.length > 0 ? (
          <div className="pw-posthead__tags">
            {tags.map((t, i) => (
              <span key={i} className="pw-tag">
                {t}
              </span>
            ))}
          </div>
        ) : null}
      </div>
    </header>
  );
}

import * as React from "react";
import {
  CalendarClock,
  Check,
  Globe,
  Heart,
  Image as ImageIcon,
  LayoutTemplate,
  type LucideIcon,
  Palette,
  PenTool,
  RefreshCw,
  Rocket,
  ShieldCheck,
  Sparkles,
  Star,
  Zap,
} from "lucide-react";

/**
 * Curated, named icon set for content blocks (e.g. feature cards).
 *
 * Content references an icon by *name* (a stable string) rather than embedding an emoji, so the
 * builder and generated Astro sites render the same crisp vector icon from a real icon library.
 * Add to this map to expose more choices in the builder's icon picker.
 */
export const blockIcons = {
  palette: Palette,
  rocket: Rocket,
  calendar: CalendarClock,
  image: ImageIcon,
  shield: ShieldCheck,
  recycle: RefreshCw,
  sparkles: Sparkles,
  zap: Zap,
  globe: Globe,
  layout: LayoutTemplate,
  pen: PenTool,
  check: Check,
  star: Star,
  heart: Heart,
} satisfies Record<string, LucideIcon>;

export type BlockIconName = keyof typeof blockIcons;

export const blockIconNames = Object.keys(blockIcons) as BlockIconName[];

/** Renders a named block icon. Unknown/empty names render nothing (safe fallback). */
export function BlockIcon({
  name,
  size = 24,
  strokeWidth = 1.75,
}: {
  name?: string;
  size?: number;
  strokeWidth?: number;
}) {
  if (!name) return null;
  const Icon = blockIcons[name as BlockIconName];
  if (!Icon) return null;
  return <Icon size={size} strokeWidth={strokeWidth} aria-hidden="true" />;
}

export * from "./schema";
export * from "./blocks";
export * from "./icons";
export * from "./base";
export { BlockRenderer, PageRenderer } from "./renderer";

import * as React from "react";
import type { Block } from "./schema";
import { blockRegistry } from "./blocks";

/** Render a single block by looking up its component in the registry. */
export function BlockRenderer({ block, base }: { block: Block; base?: string }) {
  const Component = blockRegistry[block.type] as React.FC<Record<string, unknown>>;
  if (!Component) {
    if (typeof console !== "undefined") {
      console.warn(`[pagewright] Unknown block type: ${(block as { type: string }).type}`);
    }
    return null;
  }
  return <Component {...(block.props as Record<string, unknown>)} base={base} />;
}

/**
 * Render an ordered list of blocks (a page body). `base` is the site's base path
 * (`import.meta.env.BASE_URL` in Astro); it is threaded to every block as a prop so root-relative
 * image and link URLs resolve correctly on GitHub Pages project sites. Defaults to `/`. Kept
 * context-free so blocks remain renderable as React Server Components.
 */
export function PageRenderer({ blocks, base }: { blocks: Block[]; base?: string }) {
  return (
    <>
      {blocks.map((block) => (
        <BlockRenderer key={block.id} block={block} base={base} />
      ))}
    </>
  );
}

import { z } from "zod";

/**
 * Pagewright content model.
 *
 * A page is an ordered list of typed blocks. This schema is the single source of
 * truth shared by the visual builder (Next.js) and the generated Astro sites, so
 * both render identical output and content is safe to migrate over time.
 */

export const linkSchema = z.object({
  label: z.string(),
  href: z.string(),
});
export type Link = z.infer<typeof linkSchema>;

export const navbarBlockSchema = z.object({
  type: z.literal("navbar"),
  id: z.string(),
  props: z.object({
    brand: z.string(),
    logo: z.string().optional(),
    links: z.array(linkSchema).default([]),
    cta: linkSchema.optional(),
  }),
});

export const heroBlockSchema = z.object({
  type: z.literal("hero"),
  id: z.string(),
  props: z.object({
    eyebrow: z.string().optional(),
    heading: z.string(),
    subheading: z.string().optional(),
    primaryCta: linkSchema.optional(),
    secondaryCta: linkSchema.optional(),
    image: z.string().optional(),
    align: z.enum(["left", "center"]).default("center"),
  }),
});

export const featureItemSchema = z.object({
  /** Named icon from the shared block icon set (see `blockIcons`), e.g. "rocket". */
  icon: z.string().optional(),
  title: z.string(),
  body: z.string(),
});
export type FeatureItem = z.infer<typeof featureItemSchema>;

export const featuresBlockSchema = z.object({
  type: z.literal("features"),
  id: z.string(),
  props: z.object({
    heading: z.string().optional(),
    subheading: z.string().optional(),
    columns: z.union([z.literal(2), z.literal(3), z.literal(4)]).default(3),
    items: z.array(featureItemSchema).default([]),
  }),
});

export const ctaBlockSchema = z.object({
  type: z.literal("cta"),
  id: z.string(),
  props: z.object({
    heading: z.string(),
    body: z.string().optional(),
    primaryCta: linkSchema.optional(),
    secondaryCta: linkSchema.optional(),
  }),
});

export const proseBlockSchema = z.object({
  type: z.literal("prose"),
  id: z.string(),
  props: z.object({
    /** Markdown source (canonical for posts). Rendered to `html` at save time. */
    markdown: z.string().optional(),
    /** Rendered HTML the Astro template outputs directly (kept in sync with `markdown`). */
    html: z.string().default(""),
  }),
});

export const footerBlockSchema = z.object({
  type: z.literal("footer"),
  id: z.string(),
  props: z.object({
    brand: z.string().optional(),
    tagline: z.string().optional(),
    links: z.array(linkSchema).default([]),
    copyright: z.string().optional(),
  }),
});

export const galleryItemSchema = z.object({
  title: z.string(),
  description: z.string().optional(),
  image: z.string().optional(),
  href: z.string().optional(),
  tags: z.array(z.string()).default([]),
});
export type GalleryItem = z.infer<typeof galleryItemSchema>;

export const galleryBlockSchema = z.object({
  type: z.literal("gallery"),
  id: z.string(),
  props: z.object({
    heading: z.string().optional(),
    subheading: z.string().optional(),
    columns: z.union([z.literal(2), z.literal(3)]).default(3),
    items: z.array(galleryItemSchema).default([]),
  }),
});

export const blockSchema = z.discriminatedUnion("type", [
  navbarBlockSchema,
  heroBlockSchema,
  featuresBlockSchema,
  galleryBlockSchema,
  ctaBlockSchema,
  proseBlockSchema,
  footerBlockSchema,
]);
export type Block = z.infer<typeof blockSchema>;
export type BlockType = Block["type"];
export type BlockProps<T extends BlockType> = Extract<Block, { type: T }>["props"];

export const pageSchema = z.object({
  title: z.string(),
  description: z.string().optional(),
  slug: z.string().default("/"),
  draft: z.boolean().default(false),
  publishAt: z.string().datetime().optional(),
  blocks: z.array(blockSchema).default([]),
});
export type Page = z.infer<typeof pageSchema>;

/**
 * A blog post is a page document plus blog front-matter (date, excerpt, cover, tags, author).
 * Shared by the builder, the generated Astro blog template, and the scheduled-publish workflow.
 */
export const postSchema = pageSchema.extend({
  date: z.string(),
  excerpt: z.string().optional(),
  cover: z.string().optional(),
  tags: z.array(z.string()).default([]),
  author: z.string().optional(),
});
export type Post = z.infer<typeof postSchema>;

export const siteConfigSchema = z.object({
  name: z.string(),
  description: z.string().optional(),
  url: z.string().optional(),
  defaultTheme: z.enum(["light", "dark", "system"]).default("system"),
  socials: z.array(linkSchema).default([]),
});
export type SiteConfig = z.infer<typeof siteConfigSchema>;

/** Parse + apply defaults for an unknown page document (used when reading repo content). */
export function parsePage(input: unknown): Page {
  return pageSchema.parse(input);
}

/** Parse + apply defaults for an unknown blog post document. */
export function parsePost(input: unknown): Post {
  return postSchema.parse(input);
}

/* Pagewright block styles — self-contained, token-driven, framework-agnostic.
   Works identically in the Next.js builder preview and generated Astro sites.
   Dark mode responds to either a `.dark` class (next-themes) or [data-theme="dark"] (Astro). */

:root {
  --pw-bg: 0 0% 100%;
  --pw-fg: 240 10% 12%;
  --pw-muted: 240 5% 96%;
  --pw-muted-fg: 240 4% 44%;
  --pw-card: 0 0% 100%;
  --pw-border: 240 6% 90%;
  --pw-primary: 250 84% 60%;
  --pw-primary-fg: 0 0% 100%;
  --pw-accent: 33 95% 55%;
  --pw-radius: 12px;
  --pw-container: 1120px;
  --pw-font: ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, Inter, sans-serif;
}

.dark,
[data-theme="dark"] {
  --pw-bg: 240 10% 7%;
  --pw-fg: 0 0% 98%;
  --pw-muted: 240 6% 14%;
  --pw-muted-fg: 240 5% 66%;
  --pw-card: 240 8% 11%;
  --pw-border: 240 5% 20%;
  --pw-primary: 250 90% 70%;
  --pw-primary-fg: 240 30% 8%;
  --pw-accent: 33 95% 60%;
}

.pw-root {
  background: hsl(var(--pw-bg));
  color: hsl(var(--pw-fg));
  font-family: var(--pw-font);
  line-height: 1.55;
  -webkit-font-smoothing: antialiased;
}

.pw-container {
  width: 100%;
  max-width: var(--pw-container);
  margin-inline: auto;
  padding-inline: 24px;
}

.pw-section {
  padding-block: 72px;
}

.pw-section__heading {
  font-size: clamp(1.6rem, 3vw, 2.25rem);
  font-weight: 700;
  letter-spacing: -0.02em;
  text-align: center;
  margin: 0 0 8px;
}

.pw-section__subheading {
  color: hsl(var(--pw-muted-fg));
  text-align: center;
  max-width: 640px;
  margin: 0 auto 40px;
}

/* Buttons */
.pw-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 11px 20px;
  border-radius: calc(var(--pw-radius) - 4px);
  font-weight: 600;
  font-size: 0.95rem;
  text-decoration: none;
  border: 1px solid transparent;
  transition: transform 0.06s ease, opacity 0.15s ease, background 0.15s ease;
}
.pw-btn:active { transform: translateY(1px); }
.pw-btn--primary {
  background: hsl(var(--pw-primary));
  color: hsl(var(--pw-primary-fg));
}
.pw-btn--primary:hover { opacity: 0.92; }
.pw-btn--secondary {
  background: transparent;
  color: hsl(var(--pw-fg));
  border-color: hsl(var(--pw-border));
}
.pw-btn--secondary:hover { background: hsl(var(--pw-muted)); }

/* Navbar */
.pw-navbar {
  border-bottom: 1px solid hsl(var(--pw-border));
  background: hsl(var(--pw-bg) / 0.8);
  backdrop-filter: blur(8px);
  position: sticky;
  top: 0;
  z-index: 20;
}
.pw-navbar__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 64px;
}
.pw-navbar__brand {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-weight: 700;
  color: hsl(var(--pw-fg));
  text-decoration: none;
  font-size: 1.05rem;
}
.pw-navbar__logo { height: 28px; width: auto; }
.pw-navbar__links { display: flex; align-items: center; gap: 20px; }
.pw-navbar__link {
  color: hsl(var(--pw-muted-fg));
  text-decoration: none;
  font-size: 0.95rem;
  font-weight: 500;
}
.pw-navbar__link:hover { color: hsl(var(--pw-fg)); }

/* Hero */
.pw-hero { padding-block: 96px; }
.pw-hero__inner { display: grid; gap: 40px; align-items: center; }
.pw-hero--center .pw-hero__inner { text-align: center; justify-items: center; }
.pw-hero--left .pw-hero__content { max-width: 620px; }
.pw-hero__eyebrow {
  display: inline-block;
  color: hsl(var(--pw-primary));
  font-weight: 600;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  font-size: 0.8rem;
  margin: 0 0 12px;
}
.pw-hero__heading {
  font-size: clamp(2.25rem, 5vw, 3.5rem);
  font-weight: 800;
  letter-spacing: -0.03em;
  line-height: 1.05;
  margin: 0 0 16px;
}
.pw-hero__subheading {
  font-size: clamp(1.05rem, 2vw, 1.25rem);
  color: hsl(var(--pw-muted-fg));
  max-width: 640px;
  margin: 0 0 28px;
}
.pw-hero--center .pw-hero__subheading { margin-inline: auto; }
.pw-hero__actions { display: flex; gap: 12px; flex-wrap: wrap; }
.pw-hero--center .pw-hero__actions { justify-content: center; }
.pw-hero__media img {
  width: 100%;
  height: auto;
  border-radius: var(--pw-radius);
  border: 1px solid hsl(var(--pw-border));
}

/* Features */
.pw-features__grid { display: grid; gap: 24px; }
.pw-cols-2 { grid-template-columns: repeat(2, minmax(0, 1fr)); }
.pw-cols-3 { grid-template-columns: repeat(3, minmax(0, 1fr)); }
.pw-cols-4 { grid-template-columns: repeat(4, minmax(0, 1fr)); }
.pw-feature {
  background: hsl(var(--pw-card));
  border: 1px solid hsl(var(--pw-border));
  border-radius: var(--pw-radius);
  padding: 24px;
}
.pw-feature__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 46px;
  height: 46px;
  margin-bottom: 14px;
  border-radius: 12px;
  color: hsl(var(--pw-primary));
  background: hsl(var(--pw-primary) / 0.1);
}
.pw-feature__icon svg { display: block; }
.pw-feature__title { font-size: 1.1rem; font-weight: 700; margin: 0 0 6px; }
.pw-feature__body { color: hsl(var(--pw-muted-fg)); margin: 0; font-size: 0.95rem; }

/* CTA */
.pw-cta__inner {
  background: linear-gradient(135deg, hsl(var(--pw-primary)), hsl(var(--pw-accent)));
  color: #fff;
  border-radius: calc(var(--pw-radius) + 4px);
  padding: 56px 32px;
  text-align: center;
}
.pw-cta__heading { font-size: clamp(1.6rem, 3vw, 2.25rem); font-weight: 800; margin: 0 0 12px; }
.pw-cta__body { opacity: 0.95; max-width: 560px; margin: 0 auto 24px; }
.pw-cta__actions { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; }
.pw-cta .pw-btn--secondary { color: #fff; border-color: rgba(255, 255, 255, 0.5); }
.pw-cta .pw-btn--primary { background: #fff; color: hsl(var(--pw-primary)); }

/* Prose — rich typography for markdown-rendered post/page content. Tailwind's
   Preflight resets headings/lists to unstyled, so every element is styled
   explicitly here. Token-driven so it themes in light/dark and renders
   identically in the composer preview and on deployed Astro sites. */
.pw-prose {
  max-width: 720px;
  color: hsl(var(--pw-fg));
  font-size: 1.0625rem;
  line-height: 1.75;
}
.pw-prose > :first-child { margin-top: 0; }
.pw-prose > :last-child { margin-bottom: 0; }
.pw-prose h1,
.pw-prose h2,
.pw-prose h3,
.pw-prose h4 {
  letter-spacing: -0.02em;
  font-weight: 700;
  line-height: 1.25;
  color: hsl(var(--pw-fg));
}
.pw-prose h1 { font-size: 2rem; font-weight: 800; margin: 2rem 0 1rem; }
.pw-prose h2 { font-size: 1.5rem; margin: 1.75rem 0 0.75rem; }
.pw-prose h3 { font-size: 1.25rem; margin: 1.5rem 0 0.5rem; }
.pw-prose h4 { font-size: 1.0625rem; margin: 1.25rem 0 0.5rem; }
.pw-prose p { margin: 0 0 1rem; }
.pw-prose a {
  color: hsl(var(--pw-primary));
  text-decoration: underline;
  text-underline-offset: 2px;
}
.pw-prose strong { font-weight: 700; color: hsl(var(--pw-fg)); }
.pw-prose em { font-style: italic; }
.pw-prose ul,
.pw-prose ol { margin: 0 0 1rem; padding-left: 1.5rem; }
.pw-prose ul { list-style: disc; }
.pw-prose ol { list-style: decimal; }
.pw-prose li { margin: 0.35rem 0; }
.pw-prose li > ul,
.pw-prose li > ol { margin: 0.35rem 0; }
.pw-prose blockquote {
  margin: 0 0 1rem;
  padding: 0.25rem 0 0.25rem 1rem;
  border-left: 3px solid hsl(var(--pw-border));
  color: hsl(var(--pw-muted-fg));
  font-style: italic;
}
.pw-prose code {
  font-family: ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, monospace;
  font-size: 0.9em;
  background: hsl(var(--pw-muted));
  border: 1px solid hsl(var(--pw-border));
  border-radius: 6px;
  padding: 0.1em 0.35em;
}
.pw-prose pre {
  margin: 0 0 1rem;
  padding: 1rem 1.15rem;
  background: hsl(var(--pw-muted));
  border: 1px solid hsl(var(--pw-border));
  border-radius: var(--pw-radius);
  overflow-x: auto;
  line-height: 1.6;
}
.pw-prose pre code {
  background: none;
  border: 0;
  padding: 0;
  font-size: 0.875rem;
}
.pw-prose hr {
  margin: 2rem 0;
  border: 0;
  border-top: 1px solid hsl(var(--pw-border));
}
.pw-prose img { max-width: 100%; height: auto; border-radius: var(--pw-radius); }
.pw-prose table {
  width: 100%;
  margin: 0 0 1rem;
  border-collapse: collapse;
  font-size: 0.95em;
}
.pw-prose th,
.pw-prose td {
  border: 1px solid hsl(var(--pw-border));
  padding: 0.5rem 0.75rem;
  text-align: left;
}
.pw-prose th { background: hsl(var(--pw-muted)); font-weight: 700; }

/* Footer */
.pw-footer {
  border-top: 1px solid hsl(var(--pw-border));
  padding-block: 40px 24px;
  margin-top: 40px;
}
.pw-footer__inner {
  display: flex;
  justify-content: space-between;
  gap: 24px;
  flex-wrap: wrap;
}
.pw-footer__tagline { color: hsl(var(--pw-muted-fg)); margin: 6px 0 0; font-size: 0.9rem; }
.pw-footer__links { display: flex; gap: 20px; flex-wrap: wrap; }
.pw-footer__link { color: hsl(var(--pw-muted-fg)); text-decoration: none; font-size: 0.9rem; }
.pw-footer__link:hover { color: hsl(var(--pw-fg)); }
.pw-footer__copyright { color: hsl(var(--pw-muted-fg)); font-size: 0.85rem; margin-top: 24px; }

/* Shared tags */
.pw-tag {
  display: inline-block;
  font-size: 0.72rem;
  font-weight: 600;
  padding: 2px 9px;
  border-radius: 999px;
  color: hsl(var(--pw-muted-fg));
  background: hsl(var(--pw-muted));
  border: 1px solid hsl(var(--pw-border));
}

/* Gallery (portfolio) */
.pw-gallery__grid { display: grid; gap: 24px; }
.pw-gallery__item {
  display: block;
  background: hsl(var(--pw-card));
  border: 1px solid hsl(var(--pw-border));
  border-radius: var(--pw-radius);
  overflow: hidden;
  text-decoration: none;
  color: inherit;
  transition: transform 0.15s ease, border-color 0.15s ease;
}
.pw-gallery__item--link:hover { transform: translateY(-3px); border-color: hsl(var(--pw-primary)); }
.pw-gallery__media { aspect-ratio: 16 / 10; overflow: hidden; background: hsl(var(--pw-muted)); }
.pw-gallery__media img { width: 100%; height: 100%; object-fit: cover; display: block; }
.pw-gallery__body { padding: 18px 20px 22px; }
.pw-gallery__title { font-size: 1.1rem; font-weight: 700; margin: 0 0 6px; }
.pw-gallery__desc { color: hsl(var(--pw-muted-fg)); margin: 0 0 12px; font-size: 0.95rem; }
.pw-gallery__tags { display: flex; gap: 8px; flex-wrap: wrap; }

/* Blog post list */
.pw-postlist__grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 24px;
}
.pw-postlist__empty { text-align: center; color: hsl(var(--pw-muted-fg)); }
.pw-postcard {
  display: flex;
  flex-direction: column;
  background: hsl(var(--pw-card));
  border: 1px solid hsl(var(--pw-border));
  border-radius: var(--pw-radius);
  overflow: hidden;
  text-decoration: none;
  color: inherit;
  transition: transform 0.15s ease, border-color 0.15s ease;
}
.pw-postcard:hover { transform: translateY(-3px); border-color: hsl(var(--pw-primary)); }
.pw-postcard__media { aspect-ratio: 16 / 9; overflow: hidden; background: hsl(var(--pw-muted)); }
.pw-postcard__media img { width: 100%; height: 100%; object-fit: cover; display: block; }
.pw-postcard__body { padding: 18px 20px 22px; }
.pw-postcard__date { font-size: 0.8rem; color: hsl(var(--pw-muted-fg)); }
.pw-postcard__title { font-size: 1.15rem; font-weight: 700; margin: 6px 0 8px; letter-spacing: -0.01em; }
.pw-postcard__excerpt { color: hsl(var(--pw-muted-fg)); margin: 0 0 12px; font-size: 0.95rem; }
.pw-postcard__tags { display: flex; gap: 8px; flex-wrap: wrap; }

/* Single post header */
.pw-posthead { padding: 56px 0 24px; border-bottom: 1px solid hsl(var(--pw-border)); }
.pw-posthead__inner { max-width: 720px; }
.pw-posthead__meta { color: hsl(var(--pw-muted-fg)); font-size: 0.9rem; margin-bottom: 10px; }
.pw-posthead__author { margin-left: 4px; }
.pw-posthead__title { font-size: clamp(1.8rem, 4vw, 2.6rem); font-weight: 800; letter-spacing: -0.02em; margin: 0 0 14px; }
.pw-posthead__tags { display: flex; gap: 8px; flex-wrap: wrap; }

@media (max-width: 860px) {
  .pw-cols-3, .pw-cols-4 { grid-template-columns: repeat(2, minmax(0, 1fr)); }
  .pw-postlist__grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }
  .pw-navbar__links .pw-navbar__link { display: none; }
}
@media (max-width: 560px) {
  .pw-cols-2, .pw-cols-3, .pw-cols-4 { grid-template-columns: 1fr; }
  .pw-postlist__grid { grid-template-columns: 1fr; }
}

{
  "name": "@pagewright/site-kit",
  "version": "0.1.0",
  "type": "module",
  "description": "Versioned Astro rendering kit for Pagewright sites (theme script, schema, migrations).",
  "exports": {
    ".": "./src/index.ts"
  },
  "scripts": {
    "build": "tsc --noEmit",
    "typecheck": "tsc --noEmit"
  },
  "dependencies": {
    "@pagewright/blocks": "file:../pagewright-blocks"
  },
